public &lt;T&gt; T target(Target&lt;T&gt; target) &#123;  return build().newInstance(target);&#125;    public Feign build() &#123;  SynchronousMethodHandler.Factory synchronousMethodHandlerFactory =      new SynchronousMethodHandler.Factory(client, retryer, requestInterceptors, logger,                                           logLevel, decode404);  ParseHandlersByName handlersByName =      new ParseHandlersByName(contract, options, encoder, decoder,                              errorDecoder, synchronousMethodHandlerFactory);  return new ReflectiveFeign(handlersByName, invocationHandlerFactory);&#125;
直接看ReflectiveFeign#newInstance()方法：
//ReflectiveFeign#newInstance()public &lt;T&gt; T newInstance(Target&lt;T&gt; target) &#123;	//动态代理的handler类目前穿进来的是ParseHandlersByName类，所以这里要看ParseHandlersByName#apply()直接看下一个方法	Map&lt;String, MethodHandler&gt; nameToHandler = targetToHandlersByName.apply(target);	Map&lt;Method, MethodHandler&gt; methodToHandler = new LinkedHashMap&lt;Method, MethodHandler&gt;();	List&lt;DefaultMethodHandler&gt; defaultMethodHandlers = new LinkedList&lt;DefaultMethodHandler&gt;();	for (Method method : target.type().getMethods()) &#123;    if (method.getDeclaringClass() == Object.class) &#123;      continue;    &#125; else if(Util.isDefault(method)) &#123;//默认方法会走到这里，比如toString()，hashCode()等方法      DefaultMethodHandler handler = new DefaultMethodHandler(method);      defaultMethodHandlers.add(handler);      methodToHandler.put(method, handler);    &#125; else &#123;//这里才是装配的调用类，上文分析到计息的handler是SynchronousMethodHandler#invoke()      methodToHandler.put(method, nameToHandler.get(Feign.configKey(target.type(), method)));    &#125;  &#125;  InvocationHandler handler = factory.create(target, methodToHandler);  T proxy = (T) Proxy.newProxyInstance(target.type().getClassLoader(), new Class&lt;?&gt;[]&#123;target.type()&#125;, handler);//jdk动态代理  for(DefaultMethodHandler defaultMethodHandler : defaultMethodHandlers) &#123;    defaultMethodHandler.bindTo(proxy);  &#125;  return proxy;&#125;//ParseHandlersByName#apply类，构建动态代理的handlerpublic Map&lt;String, MethodHandler&gt; apply(Target key) &#123;    List&lt;MethodMetadata&gt; metadata = contract.parseAndValidatateMetadata(key.type());    Map&lt;String, MethodHandler&gt; result = new LinkedHashMap&lt;String, MethodHandler&gt;();    for (MethodMetadata md : metadata) &#123;      BuildTemplateByResolvingArgs buildTemplate;      if (!md.formParams().isEmpty() &amp;&amp; md.template().bodyTemplate() == null) &#123;        buildTemplate = new BuildFormEncodedTemplateFromArgs(md, encoder);//通过自定义的encoder去解析参数      &#125; else if (md.bodyIndex() != null) &#123;        buildTemplate = new BuildEncodedTemplateFromArgs(md, encoder);//通过自定义的encoder去解析参数      &#125; else &#123;        buildTemplate = new BuildTemplateByResolvingArgs(md);      &#125;      //创建handler，再看Factory#create()方法，下一个方法      result.put(md.configKey(),factory.create(key, md, buildTemplate, options, decoder, errorDecoder));    &#125;    return result;  &#125;//Factory#create(),构建一个SynchronousMethodHandler去处理请求，调用invoke方法public MethodHandler create(Target&lt;?&gt; target, MethodMetadata md,        RequestTemplate.Factory buildTemplateFromArgs,        Options options, Decoder decoder, ErrorDecoder errorDecoder) &#123;    return new SynchronousMethodHandler(target, client, retryer, requestInterceptors, logger,                  logLevel, md, buildTemplateFromArgs, options, decoder,                  errorDecoder, decode404);&#125;//SynchronousMethodHandler#invoke()方法：实际调用的方法//@Overridepublic Object invoke(Object[] argv) throws Throwable &#123;    RequestTemplate template = buildTemplateFromArgs.create(argv);//构建requestTemplate对象    Retryer retryer = this.retryer.clone();    while (true) &#123;      try &#123;        return executeAndDecode(template);//下面不分析了，就是执行execute方法并且解码饭后返回值      &#125; catch (RetryableException e) &#123;        retryer.continueOrPropagate(e);        if (logLevel != Logger.Level.NONE) &#123;          logger.logRetry(metadata.configKey(), logLevel);        &#125;        continue;      &#125;    &#125;  &#125;

