private static final List&lt;BeanBinder&gt; BEAN_BINDERS;static &#123;	List&lt;BeanBinder&gt; binders = new ArrayList&lt;&gt;();	binders.add(new JavaBeanBinder());	BEAN_BINDERS = Collections.unmodifiableList(binders);&#125;public &lt;T&gt; T bind(ConfigurationPropertyName name, Bindable&lt;T&gt; target, Context context,		BeanPropertyBinder propertyBinder) &#123;	boolean hasKnownBindableProperties = hasKnownBindableProperties(name, context);	Bean&lt;T&gt; bean = Bean.get(target, hasKnownBindableProperties);	if (bean == null) &#123;		return null;	&#125;	BeanSupplier&lt;T&gt; beanSupplier = bean.getSupplier(target);	boolean bound = bind(propertyBinder, bean, beanSupplier);	return (bound ? beanSupplier.get() : null);&#125;// 返回对应的对象public BeanSupplier&lt;T&gt; getSupplier(Bindable&lt;T&gt; target) &#123;	return new BeanSupplier&lt;&gt;(() -&gt; &#123;		T instance = null;		if (target.getValue() != null) &#123;			instance = target.getValue().get();		&#125;		if (instance == null) &#123;			instance = (T) BeanUtils.instantiateClass(this.resolvedType);		&#125;		return instance;	&#125;);&#125;

